-- ============================================================
-- SparePartSearch — catalogue étendu industrie + informatique
-- 265 pièces, 15 fabricants, 11 vendeurs.
-- À coller dans le SQL Editor de Neon et exécuter en une fois.
-- VIDE les données existantes puis insère le nouveau catalogue.
-- (Les tables doivent déjà exister — créées lors du premier setup.)
-- ============================================================

TRUNCATE offers, compatibilities, supersessions, part_references, parts, sellers, categories, manufacturers RESTART IDENTITY CASCADE;









SELECT setval('manufacturers_id_seq', (SELECT COALESCE(MAX(id), 1) FROM manufacturers));
SELECT setval('categories_id_seq', (SELECT COALESCE(MAX(id), 1) FROM categories));
SELECT setval('parts_id_seq', (SELECT COALESCE(MAX(id), 1) FROM parts));
SELECT setval('part_references_id_seq', (SELECT COALESCE(MAX(id), 1) FROM part_references));
SELECT setval('supersessions_id_seq', (SELECT COALESCE(MAX(id), 1) FROM supersessions));
SELECT setval('compatibilities_id_seq', (SELECT COALESCE(MAX(id), 1) FROM compatibilities));
SELECT setval('sellers_id_seq', (SELECT COALESCE(MAX(id), 1) FROM sellers));
SELECT setval('offers_id_seq', (SELECT COALESCE(MAX(id), 1) FROM offers));
